// Normalize Input — Wax | Wane bulk listing generator
function parseCsv(text) {
  const rows = [];
  let row = [];
  let cell = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQuotes) {
      if (c === '"' && text[i + 1] === '"') { cell += '"'; i++; }
      else if (c === '"') { inQuotes = false; }
      else { cell += c; }
    } else {
      if (c === '"') inQuotes = true;
      else if (c === ',') { row.push(cell); cell = ''; }
      else if (c === '\n') { row.push(cell); rows.push(row); row = []; cell = ''; }
      else if (c === '\r') { /* ignore */ }
      else cell += c;
    }
  }
  if (cell.length > 0 || row.length > 0) { row.push(cell); rows.push(row); }
  if (!rows.length) return [];
  const header = rows.shift().map(h => h.trim());
  return rows
    .filter(r => r.some(v => v && v.trim().length))
    .map(r => Object.fromEntries(header.map((h, i) => [h, (r[i] ?? '').trim()])));
}

function asArray(v) {
  if (v == null) return [];
  if (Array.isArray(v)) return v.filter(Boolean).map(s => String(s).trim()).filter(Boolean);
  if (typeof v === 'string') {
    return v.split(/\r?\n|\||;/).map(s => s.trim()).filter(Boolean);
  }
  return [String(v)];
}

function normalize(raw, idx) {
  const sku = String(raw.sku || raw.SKU || raw.itemSku || raw.item_sku || `WW-${Date.now()}-${idx + 1}`).trim();
  const productName = String(raw.productName || raw.product_name || raw.name || raw.title || '').trim();
  const brand = String(raw.brand || raw.brand_name || 'Wax | Wane').trim();
  const brandLine = String(raw.brandLine || raw.brand_line || raw.line || '').trim();
  const category = String(raw.category || raw.product_type || raw.feed_product_type || '').trim();
  const sizeLabel = String(raw.size || raw.size_label || '').trim();
  const colorLabel = String(raw.color || '').trim();
  const price = Number(raw.price ?? raw.standard_price ?? raw.list_price ?? 0) || 0;
  const quantity = Number(raw.quantity ?? raw.qty ?? 0) || 0;
  const weightLb = Number(raw.weightLb ?? raw.shipping_weight ?? raw.weight ?? 0) || 0;
  const productId = String(raw.productId || raw.gtin || raw.upc || raw.ean || raw.external_product_id || '').trim();
  const productIdType = String(raw.productIdType || raw.external_product_id_type || (productId.length === 12 ? 'UPC' : productId.length === 13 ? 'EAN' : productId ? 'GTIN' : '')).trim();
  const manufacturer = String(raw.manufacturer || brand).trim();
  const partNumber = String(raw.partNumber || raw.part_number || sku).trim();
  const mainImageUrl = String(raw.mainImageUrl || raw.main_image_url || raw.image || '').trim();
  const features = asArray(raw.features || raw.bullets || raw.bullet_points);
  const ingredients = asArray(raw.ingredients);
  const targetAudience = asArray(raw.targetAudience || raw.target_audience_keywords);
  const keywords = asArray(raw.keywords || raw.generic_keywords);
  const specs = (raw.specs && typeof raw.specs === 'object') ? raw.specs : {};
  const shortSummary = String(raw.shortSummary || raw.summary || '').trim();
  const longDescription = String(raw.longDescription || raw.description || raw.product_description || '').trim();

  return {
    sku, productName, brand, brandLine, category,
    sizeLabel, colorLabel, price, quantity, weightLb,
    productId, productIdType, manufacturer, partNumber, mainImageUrl,
    features, ingredients, targetAudience, keywords, specs,
    shortSummary, longDescription,
  };
}

const out = [];
for (const item of items) {
  const body = item.json || {};
  let rawList = [];
  if (Array.isArray(body)) rawList = body;
  else if (Array.isArray(body.items)) rawList = body.items;
  else if (typeof body.csv === 'string' && body.csv.includes(',')) rawList = parseCsv(body.csv);
  else if (body.productName || body.product_name || body.sku) rawList = [body];
  else if (body.body && (Array.isArray(body.body.items) || body.body.productName)) {
    rawList = Array.isArray(body.body.items) ? body.body.items : [body.body];
  }

  if (!rawList.length) {
    throw new Error('No products found in input. Provide { items: [...] } or a CSV string in `csv`.');
  }
  rawList.forEach((raw, idx) => out.push({ json: normalize(raw, idx) }));
}

return out;

const LIMITS = {
  amazon:  { title: 200, bullet: 500, description: 2000, keywords: 250 },
  walmart: { name: 199,  short: 1000, long: 4000, feature: 500 },
};

const HYPE = [
  'amazing','best ever','must-have','life-changing','revolutionary','game-changer',
  'world-class','incredible','unbelievable','jaw-dropping','perfect','flawless',
  'cheap','bargain','deal','sale','% off','guaranteed',
];
const EMOJI_RE = /[\p{Extended_Pictographic}\u200d]/gu;

function dehype(s) {
  if (!s) return '';
  let out = String(s).replace(EMOJI_RE, '').replace(/!+/g, '.').replace(/\s+/g, ' ').trim();
  for (const h of HYPE) {
    const re = new RegExp(`\\b${h.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'gi');
    out = out.replace(re, '');
  }
  return out.replace(/\s+/g, ' ').replace(/\s+([.,;:])/g, '$1').trim();
}

function clip(s, max) {
  s = dehype(s);
  if (!s) return '';
  if (s.length <= max) return s;
  const cut = s.slice(0, max);
  const lastBreak = Math.max(cut.lastIndexOf('. '), cut.lastIndexOf(', '), cut.lastIndexOf(' '));
  return (lastBreak > max * 0.6 ? cut.slice(0, lastBreak) : cut).replace(/[\s,;:.\-]+$/g, '').trim();
}

function titleCase(s) {
  const small = new Set(['a','an','and','as','at','but','by','for','in','of','on','or','the','to','vs','with']);
  return String(s || '').split(/\s+/).map((w, i) => {
    const lw = w.toLowerCase();
    if (i > 0 && small.has(lw)) return lw;
    return lw.charAt(0).toUpperCase() + lw.slice(1);
  }).join(' ');
}

function isHaramoon(p) {
  const blob = `${p.brandLine || ''} ${p.brand || ''} ${p.category || ''}`.toLowerCase();
  return /haramoon/.test(blob);
}

function brandSuffixFor(p) {
  if (!isHaramoon(p)) return '';
  return ' | Wax | Wane';
}

function buildTitle(p, hardCap) {
  const head = titleCase(p.productName || 'Untitled Product');
  const descriptor = p.specs && p.specs.descriptor ? titleCase(p.specs.descriptor) : '';
  const formatBits = [];
  if (descriptor) formatBits.push(descriptor);
  if (p.colorLabel) formatBits.push(titleCase(p.colorLabel));
  if (p.sizeLabel) formatBits.push(p.sizeLabel);

  let title = [head, ...formatBits].filter(Boolean).join(' — ');
  title = dehype(title);

  const suffix = brandSuffixFor(p);
  if (suffix) {
    if (title.length + suffix.length > hardCap) {
      title = clip(title, hardCap - suffix.length);
    }
    title = title + suffix;
  } else {
    title = clip(title, hardCap);
  }
  return title;
}

function defaultFeatures(p) {
  const ing = (p.ingredients || []).slice(0, 3).join(', ');
  const aud = (p.targetAudience && p.targetAudience.length) ? p.targetAudience[0] : 'considered routines';
  return [
    p.specs && p.specs.benefitOne ? p.specs.benefitOne : 'Calibrated formulation; restrained, measured performance with no excess.',
    ing ? `Anchored in ${ing}.` : 'Composition selected for clarity, not noise.',
    `Built for ${aud}.`,
    'Considered packaging; minimal, recyclable substrate where format permits.',
    'Quality-controlled in small lots; each unit batch-verified before release.',
  ];
}

function buildBullets(p, hardCap) {
  let raw = (p.features && p.features.length ? p.features : defaultFeatures(p)).slice(0, 5);
  while (raw.length < 5) raw = raw.concat(defaultFeatures(p)).slice(0, 5);
  return raw.map(b => {
    let s = dehype(b);
    s = s.charAt(0).toUpperCase() + s.slice(1);
    if (!/[.?]$/.test(s)) s += '.';
    return clip(s, Math.min(hardCap, 250));
  });
}

function buildShortDescription(p, hardCap) {
  if (p.shortSummary) return clip(p.shortSummary, hardCap);
  const aud = p.targetAudience && p.targetAudience[0] ? p.targetAudience[0] : 'considered routines';
  const ing = (p.ingredients || []).slice(0, 3).join(', ');
  const s = `${titleCase(p.productName)} — a measured, polished addition to ${aud}.${
    ing ? ` Composition: ${ing}.` : ''
  } Performance is restrained, never theatrical.`;
  return clip(s, hardCap);
}

function buildLongDescription(p, hardCap) {
  if (p.longDescription) return clip(p.longDescription, hardCap);
  const ing = (p.ingredients || []).join(', ');
  const aud = (p.targetAudience || []).join(', ');
  const paras = [
    `${titleCase(p.productName)} is built around clarity. Formulation, finish, and feel are tuned for measured performance — the quiet kind of luxury that does not announce itself.`,
    ing ? `Composition: ${ing}.` : '',
    aud ? `Designed for: ${aud}.` : '',
    'Each unit is small-lot, batch-verified, and shipped in considered packaging. Use as part of a deliberate routine; pair with complementary steps from the same line for cohesive results.',
  ].filter(Boolean);
  return clip(paras.join('\n\n'), hardCap);
}

function buildKeywords(p, hardCap) {
  const base = new Set((p.keywords || []).map(s => s.toLowerCase()));
  for (const w of (p.targetAudience || [])) base.add(String(w).toLowerCase());
  for (const w of (p.ingredients || [])) base.add(String(w).toLowerCase());
  if (isHaramoon(p)) { base.add('haramoon'); base.add('skincare'); }
  return clip(Array.from(base).join(' '), hardCap);
}

const out = [];
for (const item of items) {
  const p = item.json;

  const amazonTitle = buildTitle(p, LIMITS.amazon.title);
  const walmartName = buildTitle(p, LIMITS.walmart.name);
  const bullets    = buildBullets(p, LIMITS.amazon.bullet);
  const shortDesc  = buildShortDescription(p, LIMITS.walmart.short);
  const longDesc   = buildLongDescription(p, Math.max(LIMITS.amazon.description, LIMITS.walmart.long));
  const keywords   = buildKeywords(p, LIMITS.amazon.keywords);

  out.push({
    json: {
      ...p,
      copy: {
        amazonTitle,
        walmartName,
        bullets,
        shortDescription: shortDesc,
        longDescription: clip(longDesc, LIMITS.walmart.long),
        amazonDescription: clip(longDesc, LIMITS.amazon.description),
        keywords,
        brandSuffixApplied: Boolean(brandSuffixFor(p)),
        isHaramoonLine: isHaramoon(p),
      },
      voice: {
        style: 'Clinical Glow / Quiet Luxury',
        rules: {
          noExclamations: true,
          noEmojis: true,
          noHype: true,
          brandSuffix: 'Appended only to HARAMOON skincare-line titles',
        },
        limits: LIMITS,
      },
    },
  });
}
return out;

const AMAZON_HEADERS = [
  'feed_product_type','item_sku','brand_name','item_name','external_product_id',
  'external_product_id_type','manufacturer','part_number','product_description',
  'standard_price','quantity','main_image_url','bullet_point1','bullet_point2',
  'bullet_point3','bullet_point4','bullet_point5','generic_keywords','item_type',
  'target_audience_keywords',
];

const WALMART_HEADERS = [
  'SKU','Product ID Type','Product ID','Product Name','Brand','Short Description',
  'Long Description','Main Image URL','Price','Shipping Weight (lb)','Site Description',
  'Key Features 1','Key Features 2','Key Features 3','Key Features 4','Key Features 5',
  'Manufacturer','Color','Size',
];

function csvEscape(v) {
  if (v == null) return '';
  const s = String(v);
  if (/[",\r\n]/.test(s)) return `"${s.replace(/"/g, '""')}"`;
  return s;
}

function rowToCsv(row, headers) {
  return headers.map(h => csvEscape(row[h])).join(',');
}

function toCsv(rows, headers) {
  const lines = [headers.join(',')];
  for (const r of rows) lines.push(rowToCsv(r, headers));
  return lines.join('\r\n') + '\r\n';
}

function toAmazonRow(p) {
  const c = p.copy || {};
  return {
    feed_product_type: p.category || 'beauty',
    item_sku: p.sku,
    brand_name: p.brand,
    item_name: c.amazonTitle,
    external_product_id: p.productId,
    external_product_id_type: p.productIdType,
    manufacturer: p.manufacturer,
    part_number: p.partNumber,
    product_description: c.amazonDescription,
    standard_price: p.price ? p.price.toFixed(2) : '',
    quantity: p.quantity || 0,
    main_image_url: p.mainImageUrl,
    bullet_point1: c.bullets[0] || '',
    bullet_point2: c.bullets[1] || '',
    bullet_point3: c.bullets[2] || '',
    bullet_point4: c.bullets[3] || '',
    bullet_point5: c.bullets[4] || '',
    generic_keywords: c.keywords,
    item_type: p.specs && p.specs.itemType ? p.specs.itemType : (p.category || 'beauty'),
    target_audience_keywords: (p.targetAudience || []).join(' '),
  };
}

function toWalmartRow(p) {
  const c = p.copy || {};
  return {
    'SKU': p.sku,
    'Product ID Type': p.productIdType,
    'Product ID': p.productId,
    'Product Name': c.walmartName,
    'Brand': p.brand,
    'Short Description': c.shortDescription,
    'Long Description': c.longDescription,
    'Main Image URL': p.mainImageUrl,
    'Price': p.price ? p.price.toFixed(2) : '',
    'Shipping Weight (lb)': p.weightLb || '',
    'Site Description': c.shortDescription,
    'Key Features 1': c.bullets[0] || '',
    'Key Features 2': c.bullets[1] || '',
    'Key Features 3': c.bullets[2] || '',
    'Key Features 4': c.bullets[3] || '',
    'Key Features 5': c.bullets[4] || '',
    'Manufacturer': p.manufacturer,
    'Color': p.colorLabel,
    'Size': p.sizeLabel,
  };
}

const all = items.map(i => i.json);
const amazonRows  = all.map(toAmazonRow);
const walmartRows = all.map(toWalmartRow);
const amazonCsv  = toCsv(amazonRows,  AMAZON_HEADERS);
const walmartCsv = toCsv(walmartRows, WALMART_HEADERS);

return [{
  json: {
    summary: {
      generatedAt: new Date().toISOString(),
      count: all.length,
      haramoonCount: all.filter(p => p.copy && p.copy.isHaramoonLine).length,
      brandSuffixApplied: all.filter(p => p.copy && p.copy.brandSuffixApplied).length,
      voice: 'Clinical Glow / Quiet Luxury',
    },
    amazon: { headers: AMAZON_HEADERS, rows: amazonRows, csv: amazonCsv },
    walmart: { headers: WALMART_HEADERS, rows: walmartRows, csv: walmartCsv },
  },
  binary: {
    amazon_listings_csv: {
      data: Buffer.from(amazonCsv, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: `wax-wane-amazon-listings-${Date.now()}.csv`,
      fileExtension: 'csv',
    },
    walmart_listings_csv: {
      data: Buffer.from(walmartCsv, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: `wax-wane-walmart-listings-${Date.now()}.csv`,
      fileExtension: 'csv',
    },
  },
}];


// TikTok Shop CSV scaffold (activate when TIKTOK_ACCESS_TOKEN is set)
const TIKTOK_HEADERS = ['sku','title','description','price','quantity','main_image_url','category','brand'];
function toTikTokRow(p) {
  const c = p.copy || {};
  return {
    sku: p.sku,
    title: (c.amazonTitle || p.productName || '').substring(0, 255),
    description: (c.shortDescription || c.amazonDescription || '').substring(0, 2000),
    price: p.price ? p.price.toFixed(2) : '',
    quantity: p.quantity || 0,
    main_image_url: p.mainImageUrl || '',
    category: p.category || 'Beauty',
    brand: p.brand || 'Wax | Wane',
  };
}
const tiktokRows = $input.all().map(i => i.json);
const tiktokCsv = toCsv(tiktokRows.map(toTikTokRow), TIKTOK_HEADERS);
const base = $input.first().json;
return [{ json: { ...base, tiktokCsv, tiktokRowCount: tiktokRows.length, tiktokNote: 'Scaffold — upload via TikTok Seller Center until API token active' } }];

const EXCLUDE_VENDORS = ['lnk.nebraska', 'lnk nebraska'];
const out = [];
for (const item of $input.all()) {
  const p = item.json;
  if (p.skip) { out.push(item); continue; }
  const v = String(p.brand || p.vendor || '').toLowerCase();
  if (EXCLUDE_VENDORS.some(x => v.includes(x))) continue;
  out.push(item);
}
return out.length ? out : [{ json: { skip: true, message: 'All rows filtered (LNK excluded)' } }];

const products = $input.first().json.products || [];
const EXCLUDE = ['lnk.nebraska','lnk nebraska','lnk'];
const rows = [];
for (const p of products) {
  const v = (p.vendor || '').toLowerCase();
  if (EXCLUDE.some(e => v.includes(e))) continue;
  const variant = (p.variants || [])[0] || {};
  rows.push({ json: {
    sku: variant.sku || `WW-${p.id}`,
    productName: p.title,
    brand: p.vendor || 'Wax | Wane',
    category: p.product_type || 'beauty',
    price: parseFloat(variant.price) || 0,
    quantity: variant.inventory_quantity || 0,
    mainImageUrl: (p.images || [])[0]?.src || '',
    productId: variant.barcode || '',
    productIdType: variant.barcode ? 'UPC' : '',
    bodyHtml: p.body_html || '',
  }});
}
return rows.length ? rows : [{ json: { skip: true, message: 'No eligible products' } }];
